import json, glob
want = {
 "casper2023_open_problems_rlhf":"Open Problems and Fundamental Limitations of Reinforcement",
 "content_importance_2020_summarization":"Modeling Content Importance",
 "framing2025_comparing_humans_llms":"Comparing the Framing Effect",
 "linear_probe2024_reduce_sycophancy":"Linear Probe Penalties",
 "syceval2025_evaluating_sycophancy":"SycEval",
 "truthdecay2025_multiturn_sycophancy":"TRUTH DECAY",
 "are_you_sure2023_flipflop":"FlipFlop",
 "ouyang2022_instructgpt_rlhf":"follow instructions with human feedback",
}
seen={}
for fn in glob.glob("paper_search_results/full/*.json"):
    d=json.load(open(fn))
    for p in d.get("papers",[]):
        t=p.get("title","")
        for k,frag in want.items():
            if frag.lower() in t.lower() and k not in seen:
                seen[k]={"title":t,"year":p.get("year"),"authors":p.get("authors"),"abstract":(p.get("abstract") or "")[:700]}
json.dump(seen, open("papers/_screened_abstracts.json","w"), indent=2)
print("found abstracts for:", list(seen.keys()))
PYEOF
